// Simple format: "restaurants in London, 20"
const msg = $input.first().json.message.text;
const parts = msg.split(',').map(p => p.trim());

const query = parts[0] || 'restaurants in London';
const limit = parseInt(parts[1]) || 10;

// Build Google Maps URL from the query — encode it properly in JS
// This bypasses Apify's IP-based geolocation completely
const encodedQuery = encodeURIComponent(query);
const mapsUrl = `https://www.google.com/maps/search/${encodedQuery}`;

return [{ json: { sector: query, limit, mapsUrl, startTime: new Date().toISOString() } }];

