// Merge node gives us both Apify leads AND existing Sheets contacts in one list.
// Apify items have 'title' (lowercase). Sheets rows have 'Title' (uppercase column header).
const allItems = $input.all();

const apifyItems  = allItems.filter(item => item.json.title  !== undefined);
const sheetsItems = allItems.filter(item => item.json['Title'] !== undefined);

// Build a set of names already in the sheet (lowercased for comparison)
const existingTitles = new Set(
  sheetsItems
    .map(item => (item.json['Title'] || '').toLowerCase().trim())
    .filter(t => t !== '')
);

// Keep only Apify leads that aren't already in the sheet
const newLeads = apifyItems.filter(item => {
  const title = (item.json.title || '').toLowerCase().trim();
  return !existingTitles.has(title);
});

return newLeads.length > 0 ? newLeads : [];

